  PRIMARY KEY (`id`),
  UNIQUE KEY `code` (`code`),
  KEY `fold_type_id` (`fold_type_id`),
  KEY `sim_type_id` (`sim_type_id`),
  KEY `default_param_group_id` (`default_param_group_id`),
  KEY `default_cond_out_group_id` (`default_cond_out_group_id`),
